/**
 * Apotheca Marketing Suite — Visual Email Editor + Campaign Manager (React SPA)
 * Uses wp-element (React), wp-components, wp-api-fetch.
 *
 * Block types: text, image, button, divider, spacer, product-card,
 *   reviews, social-links, unsubscribe-footer
 *
 * Layout wrappers: single (600px), 50/50, 60/40, three-column
 * Montserrat brand font with full fallback stack.
 * MSO conditional comments for Outlook. Mobile media queries.
 */
(function () {
    'use strict';

    var el = wp.element.createElement;
    var useState = wp.element.useState;
    var useEffect = wp.element.useEffect;
    var useCallback = wp.element.useCallback;
    var useRef = wp.element.useRef;
    var Fragment = wp.element.Fragment;
    var Button = wp.components.Button;
    var TextControl = wp.components.TextControl;
    var SelectControl = wp.components.SelectControl;
    var TextareaControl = wp.components.TextareaControl;
    var ToggleControl = wp.components.ToggleControl;
    var RangeControl = wp.components.RangeControl;
    var ColorPicker = wp.components.ColorPicker;
    var Notice = wp.components.Notice;
    var Spinner = wp.components.Spinner;
    var Card = wp.components.Card;
    var CardHeader = wp.components.CardHeader;
    var CardBody = wp.components.CardBody;
    var TabPanel = wp.components.TabPanel;
    var apiFetch = wp.apiFetch;
    var cfg = window.amsEmailEditor || {};

    var FONT_STACK = "'Montserrat','Century Gothic','Trebuchet MS',Arial,Helvetica,sans-serif";
    var FONT_IMPORT = "@import url('https://fonts.googleapis.com/css2?family=Montserrat:ital,wght@0,300;0,400;0,500;0,600;0,700;0,800;1,400;1,700&display=swap');";

    var BLOCK_TYPES = [
        { type: 'text', label: 'Text' },
        { type: 'image', label: 'Image' },
        { type: 'button', label: 'Button' },
        { type: 'divider', label: 'Divider' },
        { type: 'spacer', label: 'Spacer' },
        { type: 'product-card', label: 'Product Card' },
        { type: 'reviews', label: 'Reviews' },
        { type: 'social-links', label: 'Social Links' },
        { type: 'unsubscribe-footer', label: 'Unsubscribe Footer' },
    ];

    var LAYOUT_TYPES = [
        { value: 'single', label: 'Single Column (600px)' },
        { value: '50-50', label: '50/50' },
        { value: '60-40', label: '60/40' },
        { value: 'three-col', label: 'Three Column' },
    ];

    var REVIEW_MODES = [
        { value: 'review_request', label: 'Review Request CTA' },
        { value: 'social_proof', label: 'Social Proof Cards' },
        { value: 'review_gate', label: 'Star Rating Gate' },
    ];

    /* ── Default block data factories ── */
    function createBlock(type) {
        var base = { id: 'b' + Date.now() + Math.random().toString(36).slice(2, 6), type: type };
        switch (type) {
            case 'text': return Object.assign(base, { content: '<p>Enter your text here...</p>', align: 'left' });
            case 'image': return Object.assign(base, { src: '', alt: '', width: '100%', align: 'center', link: '' });
            case 'button': return Object.assign(base, { text: 'Click Here', url: '#', bgColor: '#2271b1', textColor: '#ffffff', borderRadius: '4px', align: 'center', padding: '12px 24px' });
            case 'divider': return Object.assign(base, { color: '#cccccc', thickness: '1px', style: 'solid', width: '100%' });
            case 'spacer': return Object.assign(base, { height: 20 });
            case 'product-card': return Object.assign(base, { productName: '{{product_name}}', productUrl: '{{product_url}}', imageUrl: '{{product_image_url}}', price: '{{product_price}}', buttonText: 'Shop Now', buttonColor: '#2271b1' });
            case 'reviews': return Object.assign(base, { mode: 'review_request', heading: 'How was your purchase?', buttonText: 'Leave a Review', buttonColor: '#2271b1' });
            case 'social-links': return Object.assign(base, { facebook: '#', instagram: '#', twitter: '#', youtube: '', align: 'center' });
            case 'unsubscribe-footer': return Object.assign(base, { text: 'You received this email because you opted in at {{shop_name}}.', linkText: 'Unsubscribe', align: 'center' });
            default: return base;
        }
    }

    /* ── Block Settings Panel ── */
    function BlockSettings(props) {
        var block = props.block;
        var onChange = props.onChange;
        var onRemove = props.onRemove;
        var onMoveUp = props.onMoveUp;
        var onMoveDown = props.onMoveDown;

        function upd(patch) { onChange(Object.assign({}, block, patch)); }

        var fields = [];

        switch (block.type) {
            case 'text':
                fields.push(el(TextareaControl, { key: 'content', label: 'Content (HTML)', value: block.content, onChange: function (v) { upd({ content: v }); }, rows: 6, __nextHasNoMarginBottom: true }));
                fields.push(el(SelectControl, { key: 'align', label: 'Alignment', value: block.align, options: [{ value: 'left', label: 'Left' }, { value: 'center', label: 'Center' }, { value: 'right', label: 'Right' }], onChange: function (v) { upd({ align: v }); }, __nextHasNoMarginBottom: true }));
                break;
            case 'image':
                fields.push(el(TextControl, { key: 'src', label: 'Image URL', value: block.src, onChange: function (v) { upd({ src: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'alt', label: 'Alt Text', value: block.alt, onChange: function (v) { upd({ alt: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'link', label: 'Link URL', value: block.link, onChange: function (v) { upd({ link: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'width', label: 'Width', value: block.width, onChange: function (v) { upd({ width: v }); }, __nextHasNoMarginBottom: true }));
                break;
            case 'button':
                fields.push(el(TextControl, { key: 'text', label: 'Button Text', value: block.text, onChange: function (v) { upd({ text: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'url', label: 'URL', value: block.url, onChange: function (v) { upd({ url: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'bgColor', label: 'Background Color', value: block.bgColor, onChange: function (v) { upd({ bgColor: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'textColor', label: 'Text Color', value: block.textColor, onChange: function (v) { upd({ textColor: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'borderRadius', label: 'Border Radius', value: block.borderRadius, onChange: function (v) { upd({ borderRadius: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'padding', label: 'Padding', value: block.padding, onChange: function (v) { upd({ padding: v }); }, __nextHasNoMarginBottom: true }));
                break;
            case 'divider':
                fields.push(el(TextControl, { key: 'color', label: 'Color', value: block.color, onChange: function (v) { upd({ color: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'thickness', label: 'Thickness', value: block.thickness, onChange: function (v) { upd({ thickness: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(SelectControl, { key: 'style', label: 'Style', value: block.style, options: [{ value: 'solid', label: 'Solid' }, { value: 'dashed', label: 'Dashed' }, { value: 'dotted', label: 'Dotted' }], onChange: function (v) { upd({ style: v }); }, __nextHasNoMarginBottom: true }));
                break;
            case 'spacer':
                fields.push(el(RangeControl, { key: 'height', label: 'Height (px)', value: block.height, onChange: function (v) { upd({ height: v }); }, min: 5, max: 100, __nextHasNoMarginBottom: true }));
                break;
            case 'product-card':
                fields.push(el(TextControl, { key: 'productName', label: 'Product Name', value: block.productName, onChange: function (v) { upd({ productName: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'productUrl', label: 'Product URL', value: block.productUrl, onChange: function (v) { upd({ productUrl: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'imageUrl', label: 'Image URL', value: block.imageUrl, onChange: function (v) { upd({ imageUrl: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'price', label: 'Price', value: block.price, onChange: function (v) { upd({ price: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'buttonText', label: 'Button Text', value: block.buttonText, onChange: function (v) { upd({ buttonText: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'buttonColor', label: 'Button Color', value: block.buttonColor, onChange: function (v) { upd({ buttonColor: v }); }, __nextHasNoMarginBottom: true }));
                break;
            case 'reviews':
                fields.push(el(SelectControl, { key: 'mode', label: 'Review Mode', value: block.mode, options: REVIEW_MODES, onChange: function (v) { upd({ mode: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'heading', label: 'Heading', value: block.heading, onChange: function (v) { upd({ heading: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'buttonText', label: 'Button Text', value: block.buttonText, onChange: function (v) { upd({ buttonText: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'buttonColor', label: 'Button Color', value: block.buttonColor, onChange: function (v) { upd({ buttonColor: v }); }, __nextHasNoMarginBottom: true }));
                break;
            case 'social-links':
                fields.push(el(TextControl, { key: 'facebook', label: 'Facebook URL', value: block.facebook, onChange: function (v) { upd({ facebook: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'instagram', label: 'Instagram URL', value: block.instagram, onChange: function (v) { upd({ instagram: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'twitter', label: 'X/Twitter URL', value: block.twitter, onChange: function (v) { upd({ twitter: v }); }, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'youtube', label: 'YouTube URL', value: block.youtube, onChange: function (v) { upd({ youtube: v }); }, __nextHasNoMarginBottom: true }));
                break;
            case 'unsubscribe-footer':
                fields.push(el(TextareaControl, { key: 'text', label: 'Footer Text', value: block.text, onChange: function (v) { upd({ text: v }); }, rows: 3, __nextHasNoMarginBottom: true }));
                fields.push(el(TextControl, { key: 'linkText', label: 'Link Text', value: block.linkText, onChange: function (v) { upd({ linkText: v }); }, __nextHasNoMarginBottom: true }));
                break;
        }

        return el('div', { style: { padding: '12px', borderBottom: '1px solid #ddd' } },
            el('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '8px' } },
                el('strong', {}, block.type.toUpperCase()),
                el('div', { style: { display: 'flex', gap: '4px' } },
                    el(Button, { isSmall: true, onClick: onMoveUp, variant: 'secondary' }, '\u2191'),
                    el(Button, { isSmall: true, onClick: onMoveDown, variant: 'secondary' }, '\u2193'),
                    el(Button, { isSmall: true, isDestructive: true, onClick: onRemove, variant: 'secondary' }, '\u2715')
                )
            ),
            fields
        );
    }

    /* ── HTML Generator ── */
    function generateBlockHtml(block, settings) {
        var font = FONT_STACK;
        var textColor = settings.textColor || '#333333';
        var linkColor = settings.linkColor || '#2271b1';

        switch (block.type) {
            case 'text':
                return '<div style="text-align:' + (block.align || 'left') + ';font-family:' + font + ';color:' + textColor + ';font-size:' + (settings.fontSize || '16px') + ';line-height:1.6;">' + block.content + '</div>';
            case 'image':
                var img = '<img src="' + (block.src || '') + '" alt="' + (block.alt || '') + '" style="max-width:' + (block.width || '100%') + ';height:auto;display:block;margin:0 auto;" />';
                if (block.link) img = '<a href="' + block.link + '" target="_blank">' + img + '</a>';
                return '<div style="text-align:' + (block.align || 'center') + ';">' + img + '</div>';
            case 'button':
                return '<div style="text-align:' + (block.align || 'center') + ';padding:10px 0;"><a href="' + (block.url || '#') + '" target="_blank" style="display:inline-block;background:' + (block.bgColor || '#2271b1') + ';color:' + (block.textColor || '#fff') + ';font-family:' + font + ';font-size:16px;font-weight:600;text-decoration:none;padding:' + (block.padding || '12px 24px') + ';border-radius:' + (block.borderRadius || '4px') + ';mso-padding-alt:0;text-align:center;">' +
                    '<!--[if mso]><i style="letter-spacing:24px;mso-font-width:-100%;mso-text-raise:18pt;">&nbsp;</i><![endif]--><span style="mso-text-raise:9pt;">' + (block.text || 'Click') + '</span><!--[if mso]><i style="letter-spacing:24px;mso-font-width:-100%;">&nbsp;</i><![endif]-->' +
                    '</a></div>';
            case 'divider':
                return '<hr style="border:0;border-top:' + (block.thickness || '1px') + ' ' + (block.style || 'solid') + ' ' + (block.color || '#ccc') + ';width:' + (block.width || '100%') + ';margin:10px auto;" />';
            case 'spacer':
                return '<div style="height:' + (block.height || 20) + 'px;line-height:' + (block.height || 20) + 'px;">&nbsp;</div>';
            case 'product-card':
                return '<table cellpadding="0" cellspacing="0" border="0" width="100%" style="font-family:' + font + ';"><tr>' +
                    '<td style="width:40%;padding:10px;"><img src="' + (block.imageUrl || '') + '" alt="' + (block.productName || '') + '" style="max-width:100%;height:auto;" /></td>' +
                    '<td style="width:60%;padding:10px;vertical-align:top;">' +
                    '<h3 style="margin:0 0 8px;font-family:' + font + ';color:' + textColor + ';">' + (block.productName || 'Product') + '</h3>' +
                    '<p style="margin:0 0 12px;font-family:' + font + ';color:' + textColor + ';font-size:18px;font-weight:600;">' + (block.price || '') + '</p>' +
                    '<a href="' + (block.productUrl || '#') + '" target="_blank" style="display:inline-block;background:' + (block.buttonColor || '#2271b1') + ';color:#fff;font-family:' + font + ';font-size:14px;font-weight:600;text-decoration:none;padding:10px 20px;border-radius:4px;">' + (block.buttonText || 'Shop Now') + '</a>' +
                    '</td></tr></table>';
            case 'reviews':
                var reviewHtml = '<div style="text-align:center;padding:20px;font-family:' + font + ';background:#f9f9f9;border-radius:8px;">';
                reviewHtml += '<h3 style="margin:0 0 12px;font-family:' + font + ';color:' + textColor + ';">' + (block.heading || 'Reviews') + '</h3>';
                if (block.mode === 'review_request') {
                    reviewHtml += '<p style="font-family:' + font + ';color:#666;margin:0 0 16px;">We\u2019d love to hear what you think about your recent purchase.</p>';
                    reviewHtml += '<a href="#" target="_blank" style="display:inline-block;background:' + (block.buttonColor || '#2271b1') + ';color:#fff;font-family:' + font + ';font-size:14px;font-weight:600;text-decoration:none;padding:12px 24px;border-radius:4px;">' + (block.buttonText || 'Leave a Review') + '</a>';
                } else if (block.mode === 'social_proof') {
                    reviewHtml += '<div style="background:#fff;border:1px solid #e0e0e0;border-radius:6px;padding:16px;margin:8px 0;text-align:left;">';
                    reviewHtml += '<div style="color:#f5a623;font-size:18px;margin-bottom:4px;">\u2605\u2605\u2605\u2605\u2605</div>';
                    reviewHtml += '<p style="font-family:' + font + ';color:' + textColor + ';margin:0 0 4px;font-style:italic;">"Amazing product! Highly recommend."</p>';
                    reviewHtml += '<p style="font-family:' + font + ';color:#999;margin:0;font-size:12px;">— Placeholder Review (wired in Session 7)</p></div>';
                } else if (block.mode === 'review_gate') {
                    reviewHtml += '<p style="font-family:' + font + ';color:#666;margin:0 0 12px;">How would you rate your experience?</p>';
                    reviewHtml += '<div style="font-size:32px;letter-spacing:8px;">';
                    for (var s = 1; s <= 5; s++) {
                        reviewHtml += '<a href="#" style="text-decoration:none;color:#f5a623;" title="' + s + ' star">\u2605</a>';
                    }
                    reviewHtml += '</div>';
                }
                reviewHtml += '</div>';
                return reviewHtml;
            case 'social-links':
                var links = '';
                if (block.facebook) links += '<a href="' + block.facebook + '" target="_blank" style="display:inline-block;margin:0 8px;color:' + linkColor + ';text-decoration:none;font-family:' + font + ';">Facebook</a>';
                if (block.instagram) links += '<a href="' + block.instagram + '" target="_blank" style="display:inline-block;margin:0 8px;color:' + linkColor + ';text-decoration:none;font-family:' + font + ';">Instagram</a>';
                if (block.twitter) links += '<a href="' + block.twitter + '" target="_blank" style="display:inline-block;margin:0 8px;color:' + linkColor + ';text-decoration:none;font-family:' + font + ';">X</a>';
                if (block.youtube) links += '<a href="' + block.youtube + '" target="_blank" style="display:inline-block;margin:0 8px;color:' + linkColor + ';text-decoration:none;font-family:' + font + ';">YouTube</a>';
                return '<div style="text-align:' + (block.align || 'center') + ';padding:10px 0;">' + links + '</div>';
            case 'unsubscribe-footer':
                return '<div style="text-align:' + (block.align || 'center') + ';padding:20px 0;font-family:' + font + ';font-size:12px;color:#999;">' +
                    '<p style="margin:0 0 8px;">' + (block.text || '') + '</p>' +
                    '<a href="{{unsubscribe_url}}" style="color:' + linkColor + ';text-decoration:underline;">' + (block.linkText || 'Unsubscribe') + '</a>' +
                    '</div>';
            default:
                return '';
        }
    }

    function generateFullHtml(blocks, settings) {
        var bgColor = settings.bgColor || '#f4f4f4';
        var contentBg = settings.contentBg || '#ffffff';
        var maxWidth = settings.maxWidth || '600';
        var preheader = settings.preheader || '';
        var font = FONT_STACK;

        var bodyContent = '';
        blocks.forEach(function (block) {
            bodyContent += '<tr><td style="padding:0 20px;">' + generateBlockHtml(block, settings) + '</td></tr>';
        });

        return '<!DOCTYPE html>\n' +
            '<html lang="en" xmlns="http://www.w3.org/1999/xhtml" xmlns:v="urn:schemas-microsoft-com:vml" xmlns:o="urn:schemas-microsoft-com:office:office">\n' +
            '<head>\n' +
            '<meta charset="utf-8">\n' +
            '<meta name="viewport" content="width=device-width, initial-scale=1.0">\n' +
            '<meta http-equiv="X-UA-Compatible" content="IE=edge">\n' +
            '<!--[if mso]><xml><o:OfficeDocumentSettings><o:AllowPNG/><o:PixelsPerInch>96</o:PixelsPerInch></o:OfficeDocumentSettings></xml><![endif]-->\n' +
            '<style>\n' +
            FONT_IMPORT + '\n' +
            '@media only screen and (max-width:' + maxWidth + 'px) {\n' +
            '  .ams-container { width:100% !important; }\n' +
            '  .ams-col { width:100% !important; display:block !important; }\n' +
            '  .ams-col-inner { padding:10px !important; }\n' +
            '  img { max-width:100% !important; height:auto !important; }\n' +
            '}\n' +
            '</style>\n' +
            '</head>\n' +
            '<body style="margin:0;padding:0;background-color:' + bgColor + ';font-family:' + font + ';">\n' +
            (preheader ? '<div style="display:none;font-size:1px;color:' + bgColor + ';line-height:1px;max-height:0px;max-width:0px;opacity:0;overflow:hidden;">' + preheader + '</div>\n' : '') +
            '<!--[if mso]><table role="presentation" cellpadding="0" cellspacing="0" border="0" width="' + maxWidth + '" align="center"><tr><td><![endif]-->\n' +
            '<table class="ams-container" role="presentation" cellpadding="0" cellspacing="0" border="0" width="' + maxWidth + '" align="center" style="max-width:' + maxWidth + 'px;margin:0 auto;background-color:' + contentBg + ';">\n' +
            bodyContent + '\n' +
            '</table>\n' +
            '<!--[if mso]></td></tr></table><![endif]-->\n' +
            '</body>\n' +
            '</html>';
    }

    function generatePlainText(blocks) {
        var text = '';
        blocks.forEach(function (block) {
            switch (block.type) {
                case 'text':
                    var t = block.content.replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n').replace(/<[^>]+>/g, '');
                    text += t + '\n\n';
                    break;
                case 'button':
                    text += block.text + ': ' + block.url + '\n\n';
                    break;
                case 'divider':
                    text += '---\n\n';
                    break;
                case 'spacer':
                    text += '\n';
                    break;
                case 'product-card':
                    text += block.productName + ' - ' + block.price + '\n' + block.productUrl + '\n\n';
                    break;
                case 'reviews':
                    text += block.heading + '\n\n';
                    break;
                case 'social-links':
                    if (block.facebook) text += 'Facebook: ' + block.facebook + '\n';
                    if (block.instagram) text += 'Instagram: ' + block.instagram + '\n';
                    if (block.twitter) text += 'X: ' + block.twitter + '\n';
                    text += '\n';
                    break;
                case 'unsubscribe-footer':
                    text += block.text + '\n{{unsubscribe_url}}\n\n';
                    break;
            }
        });
        return text.trim();
    }

    /* ── Block Preview ── */
    function BlockPreview(props) {
        var block = props.block;
        var settings = props.settings;
        var isSelected = props.isSelected;
        var onClick = props.onClick;

        return el('div', {
            onClick: onClick,
            style: {
                padding: '4px',
                border: isSelected ? '2px solid #2271b1' : '2px solid transparent',
                cursor: 'pointer',
                borderRadius: '4px',
                transition: 'border-color 0.2s',
            },
            dangerouslySetInnerHTML: { __html: generateBlockHtml(block, settings) },
        });
    }

    /* ── Email Settings Panel ── */
    function EmailSettingsPanel(props) {
        var settings = props.settings;
        var onChange = props.onChange;

        function upd(patch) { onChange(Object.assign({}, settings, patch)); }

        return el('div', { style: { padding: '12px' } },
            el('h3', { style: { marginTop: 0 } }, 'Email Settings'),
            el(TextControl, { label: 'Background Color', value: settings.bgColor, onChange: function (v) { upd({ bgColor: v }); }, __nextHasNoMarginBottom: true }),
            el(TextControl, { label: 'Content Background', value: settings.contentBg, onChange: function (v) { upd({ contentBg: v }); }, __nextHasNoMarginBottom: true }),
            el(TextControl, { label: 'Default Font', value: 'Montserrat (Apotheca brand font)', disabled: true, __nextHasNoMarginBottom: true }),
            el(SelectControl, { label: 'Font Weight', value: settings.fontWeight, options: [
                { value: '300', label: 'Light (300)' },
                { value: '400', label: 'Regular (400)' },
                { value: '500', label: 'Medium (500)' },
                { value: '600', label: 'Semi-Bold (600)' },
                { value: '700', label: 'Bold (700)' },
                { value: '800', label: 'Extra Bold (800)' },
            ], onChange: function (v) { upd({ fontWeight: v }); }, __nextHasNoMarginBottom: true }),
            el(TextControl, { label: 'Font Size', value: settings.fontSize, onChange: function (v) { upd({ fontSize: v }); }, __nextHasNoMarginBottom: true }),
            el(TextControl, { label: 'Text Color', value: settings.textColor, onChange: function (v) { upd({ textColor: v }); }, __nextHasNoMarginBottom: true }),
            el(TextControl, { label: 'Link Color', value: settings.linkColor, onChange: function (v) { upd({ linkColor: v }); }, __nextHasNoMarginBottom: true }),
            el(TextControl, { label: 'Max Width (px)', value: settings.maxWidth, onChange: function (v) { upd({ maxWidth: v }); }, type: 'number', __nextHasNoMarginBottom: true }),
            el(TextControl, { label: 'Preheader Text', value: settings.preheader, onChange: function (v) { upd({ preheader: v }); }, __nextHasNoMarginBottom: true })
        );
    }

    /* ── Full Email Editor ── */
    function EmailEditor(props) {
        var campaignId = props.campaignId || 0;
        var _blocks = useState([createBlock('text')]);
        var blocks = _blocks[0], setBlocks = _blocks[1];
        var _sel = useState(0), selectedIdx = _sel[0], setSelectedIdx = _sel[1];
        var _settings = useState({
            bgColor: '#f4f4f4', contentBg: '#ffffff', fontWeight: '400',
            fontSize: '16px', textColor: '#333333', linkColor: '#2271b1',
            maxWidth: '600', preheader: ''
        });
        var settings = _settings[0], setSettings = _settings[1];
        var _campaign = useState(null);
        var campaign = _campaign[0], setCampaign = _campaign[1];
        var _saving = useState(false), saving = _saving[0], setSaving = _saving[1];
        var _msg = useState(''), message = _msg[0], setMessage = _msg[1];
        var _loading = useState(!!campaignId), loading = _loading[0], setLoading = _loading[1];
        var _showPreview = useState(false), showPreview = _showPreview[0], setShowPreview = _showPreview[1];
        var _previewHtml = useState(''), previewHtml = _previewHtml[0], setPreviewHtml = _previewHtml[1];

        /* Load campaign */
        useEffect(function () {
            if (!campaignId) { setLoading(false); return; }
            apiFetch({
                path: '/ams/v1/admin/campaigns/' + campaignId,
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(function (c) {
                setCampaign(c);
                if (c._blocks_json) {
                    try {
                        var parsed = JSON.parse(c._blocks_json);
                        if (parsed.blocks) setBlocks(parsed.blocks);
                        if (parsed.settings) setSettings(parsed.settings);
                    } catch (e) { /* ignore */ }
                }
                setLoading(false);
            }).catch(function () { setLoading(false); });
        }, [campaignId]);

        function addBlock(type) {
            var newBlocks = blocks.concat([createBlock(type)]);
            setBlocks(newBlocks);
            setSelectedIdx(newBlocks.length - 1);
        }

        function updateBlock(idx, updated) {
            var newBlocks = blocks.slice();
            newBlocks[idx] = updated;
            setBlocks(newBlocks);
        }

        function removeBlock(idx) {
            var newBlocks = blocks.slice();
            newBlocks.splice(idx, 1);
            setBlocks(newBlocks);
            if (selectedIdx >= newBlocks.length) setSelectedIdx(Math.max(0, newBlocks.length - 1));
        }

        function moveBlock(idx, dir) {
            var newIdx = idx + dir;
            if (newIdx < 0 || newIdx >= blocks.length) return;
            var newBlocks = blocks.slice();
            var tmp = newBlocks[idx];
            newBlocks[idx] = newBlocks[newIdx];
            newBlocks[newIdx] = tmp;
            setBlocks(newBlocks);
            setSelectedIdx(newIdx);
        }

        function save() {
            if (!campaignId) return;
            setSaving(true);
            setMessage('');

            var html = generateFullHtml(blocks, settings);
            var text = generatePlainText(blocks);

            apiFetch({
                path: '/ams/v1/admin/campaigns/' + campaignId,
                method: 'PUT',
                headers: { 'X-WP-Nonce': cfg.nonce },
                data: {
                    body_html: html,
                    body_text: text,
                    _blocks_json: JSON.stringify({ blocks: blocks, settings: settings }),
                },
            }).then(function () {
                setSaving(false);
                setMessage('Saved!');
            }).catch(function (err) {
                setSaving(false);
                setMessage('Error: ' + (err.message || 'Save failed.'));
            });
        }

        function preview() {
            var html = generateFullHtml(blocks, settings);
            apiFetch({
                path: '/ams/v1/admin/campaigns/preview',
                method: 'POST',
                headers: { 'X-WP-Nonce': cfg.nonce },
                data: { body_html: html },
            }).then(function (res) {
                setPreviewHtml(res.html);
                setShowPreview(true);
            });
        }

        if (loading) return el('div', { style: { padding: '40px', textAlign: 'center' } }, el(Spinner));

        /* Preview overlay */
        if (showPreview) {
            return el('div', { style: { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.5)', zIndex: 100000, display: 'flex', flexDirection: 'column' } },
                el('div', { style: { background: '#fff', padding: '12px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
                    el('strong', {}, 'Email Preview'),
                    el(Button, { isPrimary: true, onClick: function () { setShowPreview(false); }, variant: 'primary' }, 'Close')
                ),
                el('iframe', {
                    srcDoc: previewHtml,
                    style: { flex: 1, border: 'none', background: '#fff' },
                })
            );
        }

        return el('div', { style: { display: 'flex', height: 'calc(100vh - 80px)', background: '#f0f0f0' } },
            /* Left sidebar — Block palette */
            el('div', { style: { width: '200px', background: '#fff', borderRight: '1px solid #c3c4c7', overflowY: 'auto', flexShrink: 0 } },
                el('div', { style: { padding: '12px' } },
                    el('h3', { style: { marginTop: 0, fontSize: '13px' } }, 'Add Block'),
                    BLOCK_TYPES.map(function (bt) {
                        return el(Button, {
                            key: bt.type,
                            isSecondary: true,
                            onClick: function () { addBlock(bt.type); },
                            style: { display: 'block', width: '100%', marginBottom: '4px', textAlign: 'left' },
                            variant: 'secondary',
                        }, bt.label);
                    })
                )
            ),

            /* Center — Canvas */
            el('div', { style: { flex: 1, overflowY: 'auto', padding: '20px', background: settings.bgColor } },
                el('div', { style: { maxWidth: settings.maxWidth + 'px', margin: '0 auto', background: settings.contentBg, borderRadius: '4px', boxShadow: '0 2px 8px rgba(0,0,0,0.1)', padding: '20px' } },
                    blocks.length === 0
                        ? el('p', { style: { textAlign: 'center', color: '#999', padding: '40px' } }, 'Add blocks from the left panel to start building your email.')
                        : blocks.map(function (block, idx) {
                            return el(BlockPreview, {
                                key: block.id,
                                block: block,
                                settings: settings,
                                isSelected: idx === selectedIdx,
                                onClick: function () { setSelectedIdx(idx); },
                            });
                        })
                )
            ),

            /* Right sidebar — Block settings + Email settings */
            el('div', { style: { width: '320px', background: '#fff', borderLeft: '1px solid #c3c4c7', overflowY: 'auto', flexShrink: 0 } },
                /* Action buttons */
                el('div', { style: { padding: '12px', borderBottom: '1px solid #ddd', display: 'flex', gap: '8px' } },
                    el(Button, { isPrimary: true, isBusy: saving, onClick: save, variant: 'primary' }, 'Save'),
                    el(Button, { isSecondary: true, onClick: preview, variant: 'secondary' }, 'Preview')
                ),
                message ? el(Notice, {
                    status: message.indexOf('Error') === 0 ? 'error' : 'success',
                    isDismissible: true,
                    onDismiss: function () { setMessage(''); },
                }, message) : null,

                /* Selected block settings */
                blocks[selectedIdx]
                    ? el(BlockSettings, {
                        block: blocks[selectedIdx],
                        onChange: function (updated) { updateBlock(selectedIdx, updated); },
                        onRemove: function () { removeBlock(selectedIdx); },
                        onMoveUp: function () { moveBlock(selectedIdx, -1); },
                        onMoveDown: function () { moveBlock(selectedIdx, 1); },
                    })
                    : null,

                /* Email settings */
                el(EmailSettingsPanel, { settings: settings, onChange: setSettings })
            )
        );
    }

    /* ── Campaign List ── */
    function CampaignsList() {
        var _s = useState([]), campaigns = _s[0], setCampaigns = _s[1];
        var _l = useState(true), loading = _l[0], setLoading = _l[1];

        function load() {
            setLoading(true);
            apiFetch({
                path: '/ams/v1/admin/campaigns',
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(function (data) {
                setCampaigns(data);
                setLoading(false);
            }).catch(function () { setLoading(false); });
        }

        useEffect(load, []);

        function deleteCampaign(id) {
            if (!confirm('Delete this campaign?')) return;
            apiFetch({
                path: '/ams/v1/admin/campaigns/' + id,
                method: 'DELETE',
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(load);
        }

        var statusColors = { draft: '#dba617', scheduled: '#2271b1', sent: '#00a32a', cancelled: '#cc1818' };

        if (loading) return el(Spinner);
        if (!campaigns.length) return el('p', {}, 'No campaigns yet. Click "Create Campaign" to get started.');

        return el('table', { className: 'widefat striped' },
            el('thead', {},
                el('tr', {},
                    el('th', {}, 'Name'),
                    el('th', {}, 'Type'),
                    el('th', {}, 'Segment'),
                    el('th', {}, 'Status'),
                    el('th', {}, 'Scheduled'),
                    el('th', {}, 'Actions')
                )
            ),
            el('tbody', {},
                campaigns.map(function (c) {
                    return el('tr', { key: c.id },
                        el('td', {},
                            el('a', {
                                href: cfg.listUrl + '&view=editor&campaign_id=' + c.id,
                                style: { fontWeight: 600 },
                            }, c.name || '(Untitled)')
                        ),
                        el('td', {}, (c.type || 'email').toUpperCase()),
                        el('td', {}, c.segment_name || '—'),
                        el('td', {},
                            el('span', { style: { color: statusColors[c.status] || '#333', fontWeight: 600 } }, (c.status || 'draft').toUpperCase())
                        ),
                        el('td', {}, c.scheduled_at || '—'),
                        el('td', {},
                            el(Button, {
                                isDestructive: true, isSmall: true, variant: 'secondary',
                                onClick: function () { deleteCampaign(c.id); },
                            }, 'Delete')
                        )
                    );
                })
            )
        );
    }

    /* ── Campaign Create Form ── */
    function CampaignCreate() {
        var _n = useState(''), name = _n[0], setName = _n[1];
        var _t = useState('email'), type = _t[0], setType = _t[1];
        var _seg = useState(''), segmentId = _seg[0], setSegmentId = _seg[1];
        var _subj = useState(''), subject = _subj[0], setSubject = _subj[1];
        var _segments = useState([]), segments = _segments[0], setSegments = _segments[1];
        var _saving = useState(false), saving = _saving[0], setSaving = _saving[1];
        var _msg = useState(''), message = _msg[0], setMessage = _msg[1];

        useEffect(function () {
            apiFetch({
                path: '/ams/v1/admin/campaigns/segments',
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(setSegments).catch(function () {});
        }, []);

        function create() {
            if (!name.trim()) { setMessage('Name is required.'); return; }
            setSaving(true);
            apiFetch({
                path: '/ams/v1/admin/campaigns',
                method: 'POST',
                headers: { 'X-WP-Nonce': cfg.nonce },
                data: { name: name, type: type, segment_id: segmentId ? parseInt(segmentId, 10) : 0, subject: subject },
            }).then(function (res) {
                window.location.href = cfg.listUrl + '&view=editor&campaign_id=' + res.id;
            }).catch(function (err) {
                setSaving(false);
                setMessage('Error: ' + (err.message || 'Create failed.'));
            });
        }

        var segOpts = [{ value: '', label: '— All Subscribers —' }];
        segments.forEach(function (s) {
            segOpts.push({ value: String(s.id), label: s.name + ' (' + s.subscriber_count + ')' });
        });

        return el('div', { style: { maxWidth: '500px' } },
            message ? el(Notice, { status: 'error', isDismissible: true, onDismiss: function () { setMessage(''); } }, message) : null,
            el(TextControl, { label: 'Campaign Name', value: name, onChange: setName, __nextHasNoMarginBottom: true }),
            el(SelectControl, { label: 'Type', value: type, options: [{ value: 'email', label: 'Email' }, { value: 'sms', label: 'SMS' }], onChange: setType, __nextHasNoMarginBottom: true }),
            el(SelectControl, { label: 'Segment', value: segmentId, options: segOpts, onChange: setSegmentId, __nextHasNoMarginBottom: true }),
            type === 'email' ? el(TextControl, { label: 'Subject Line', value: subject, onChange: setSubject, __nextHasNoMarginBottom: true }) : null,
            el('div', { style: { marginTop: '16px' } },
                el(Button, { isPrimary: true, isBusy: saving, onClick: create, variant: 'primary' }, 'Create & Open Editor')
            )
        );
    }

    /* ── Mount Points ── */
    function mount(id, component) {
        var node = document.getElementById(id);
        if (node) wp.element.render(el(component), node);
    }

    function mountEditor() {
        var node = document.getElementById('ams-email-editor');
        if (node) {
            var campaignId = parseInt(node.getAttribute('data-campaign-id'), 10) || 0;
            wp.element.render(el(EmailEditor, { campaignId: campaignId }), node);
        }
    }

    document.addEventListener('DOMContentLoaded', function () {
        mount('ams-campaigns-list', CampaignsList);
        mount('ams-campaign-create', CampaignCreate);
        mountEditor();
    });
})();
